    "/home/runner/.nuget/packages/microsoft.extensions.ai/10.4.0/lib/net10.0/Microsoft.Extensions.AI.dll"
};

foreach (var path in assemblyPaths)
{
    try
    {
        var assembly = Assembly.LoadFrom(path);
        var name = System.IO.Path.GetFileName(path);
        Console.WriteLine($"\n{'='} {name} {'='}\n");

        var types = assembly.GetExportedTypes()
            .Where(t => !t.FullName.StartsWith("System") && t.IsPublic)
            .OrderBy(t => t.Name)
            .ToList();

        Console.WriteLine($"Public Types ({types.Count}):");
        foreach (var type in types)
        {
            var kind = type.IsInterface ? "interface" : type.IsClass ? "class" : type.IsEnum ? "enum" : "struct";
            Console.WriteLine($"  [{kind}] {type.FullName}");
        }

        // Special focus on Agent-related classes
        var agentTypes = types.Where(t => t.Name.Contains("Agent") || t.Name.Contains("Invoke")).ToList();
        if (agentTypes.Any())
        {
            Console.WriteLine($"\nAgent/Invoke-related types:");
            foreach (var type in agentTypes)
            {
                Console.WriteLine($"\n  >> {type.FullName}");
                if (type.IsClass)
                {
                    var methods = type.GetMethods(BindingFlags.Public | BindingFlags.Instance | BindingFlags.Static)
                        .Where(m => !m.IsSpecialName)
                        .OrderBy(m => m.Name)
                        .ToList();

                    foreach (var method in methods.GroupBy(m => m.Name).Take(10))
                    {
                        foreach (var m in method)
                        {
                            var sig = string.Join(", ", m.GetParameters().Select(p => $"{p.ParameterType.Name} {p.Name}"));
                            Console.WriteLine($"     {m.ReturnType.Name} {m.Name}({sig})");
                        }
                    }

                    var props = type.GetProperties(BindingFlags.Public | BindingFlags.Instance);
                    if (props.Any())
                    {
                        Console.WriteLine($"     Properties:");
                        foreach (var prop in props)
                        {
                            Console.WriteLine($"       {prop.PropertyType.Name} {prop.Name}");
                        }
                    }
                }
            }
        }
    }
    catch (Exception ex)
    {
        Console.WriteLine($"Error loading {path}: {ex.Message}");
    }
}
