using System.Reflection;
using System.Linq;

var assemblyPaths = new[] {
    "/home/runner/.nuget/packages/microsoft.agents.ai/1.0.0/lib/net10.0/Microsoft.Agents.AI.dll",
    "/home/runner/.nuget/packages/microsoft.agents.ai.abstractions/1.0.0/lib/net10.0/Microsoft.Agents.AI.Abstractions.dll",
    "/home/runner/.nuget/packages/microsoft.extensions.ai/10.4.0/lib/net10.0/Microsoft.Extensions.AI.dll"
};

foreach (var path in assemblyPaths)
{
    try
    {
        var assembly = Assembly.LoadFrom(path);
        var asmName = System.IO.Path.GetFileNameWithoutExtension(path);
        Console.WriteLine($"\n========== {asmName} ==========\n");

        var types = assembly.GetExportedTypes()
            .Where(t => t.IsPublic)
            .OrderBy(t => t.Name)
            .ToList();

        Console.WriteLine($"Total public types: {types.Count}\n");

        // Show Agent-related and Options types
        var relevantTypes = types.Where(t => 
            t.Name.Contains("Agent") || 
            t.Name.Contains("Invoke") ||
            t.Name.Contains("Options") ||
            t.Name.Contains("AIFunction") ||
            t.Name.Contains("Tool")).ToList();

        if (relevantTypes.Any())
        {
            Console.WriteLine("Key Types (Agent, Invoke, Options, Tool-related):\n");
            foreach (var type in relevantTypes)
            {
                var kind = type.IsInterface ? "interface" : type.IsEnum ? "enum" : type.IsValueType ? "struct" : "class";
                Console.WriteLine($"[{kind}] {type.FullName}");

                // Show methods for classes
                if (!type.IsInterface && !type.IsEnum)
                {
                    var methods = type.GetMethods(BindingFlags.Public | BindingFlags.Instance | BindingFlags.Static | BindingFlags.DeclaredOnly)
                        .Where(m => !m.IsSpecialName)
                        .OrderBy(m => m.Name)
                        .ToList();

                    if (methods.Any())
                    {
                        foreach (var method in methods.Take(15))
                        {
                            var sig = string.Join(", ", method.GetParameters().Select(p => {
                                var pType = p.ParameterType.IsGenericType 
                                    ? p.ParameterType.Name 
                                    : p.ParameterType.Name;
                                return $"{pType} {p.Name}";
                            }));
                            Console.WriteLine($"  â†’ {method.ReturnType.Name} {method.Name}({sig})");
                        }
                        if (methods.Count > 15)
                            Console.WriteLine($"  ... and {methods.Count - 15} more methods");
                    }

                    var props = type.GetProperties(BindingFlags.Public | BindingFlags.Instance | BindingFlags.Static);
                    if (props.Any())
                    {
                        Console.WriteLine($"  Properties:");
                        foreach (var prop in props)
                        {
                            var hasGet = prop.CanRead;
                            var hasSet = prop.CanWrite;
                            var access = hasGet && hasSet ? "get;set;" : hasGet ? "get;" : "set;";
                            Console.WriteLine($"    {prop.PropertyType.Name} {prop.Name} {{ {access} }}");
                        }
                    }
                }
                else if (type.IsInterface)
                {
                    var methods = type.GetMethods();
                    if (methods.Any())
                    {
                        Console.WriteLine($"  Methods:");
                        foreach (var method in methods.Take(15))
                        {
                            var sig = string.Join(", ", method.GetParameters().Select(p => $"{p.ParameterType.Name} {p.Name}"));
                            Console.WriteLine($"    {method.ReturnType.Name} {method.Name}({sig})");
                        }
                    }
                }

                Console.WriteLine();
            }
        }

        // List all types
        Console.WriteLine($"\nAll {types.Count} Public Types:\n");
        foreach (var type in types)
        {
            var kind = type.IsInterface ? "I" : type.IsEnum ? "E" : type.IsValueType ? "S" : "C";
            Console.WriteLine($"  [{kind}] {type.FullName}");
        }
    }
    catch (Exception ex)
    {
        Console.WriteLine($"Error loading {path}: {ex.Message}");
        Console.WriteLine(ex.StackTrace);
    }
}

Console.WriteLine("\n\nDone!");
