using System.ComponentModel;
using System.Net;
using System.Text;
using System.Text.Json;
using System.Text.RegularExpressions;
using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;
using OpenAI;

var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable to your OpenAI API key.");

var modelId = Environment.GetEnvironmentVariable("OPENAI_MODEL")
    ?? "gpt-4o-mini-2024-07-18";

// --- Tool instances ---
var notebook = new Notebook();
var webSearch = new WebSearchTool();

var tools = new AITool[]
{
    AIFunctionFactory.Create(webSearch.SearchAsync),
    AIFunctionFactory.Create(webSearch.FetchPageAsync),
    AIFunctionFactory.Create(notebook.AddNote),
    AIFunctionFactory.Create(notebook.GetNotes),
};

// --- Chat client (MEAI abstraction over OpenAI) ---
IChatClient chatClient = new OpenAIClient(apiKey)
    .GetChatClient(modelId)
    .AsIChatClient();

// --- Agent ---
var agentOptions = new ChatClientAgentOptions
{
    Name = "ResearchAgent",
    Description = "An AI research agent that searches the web and summarizes findings.",
    ChatOptions = new ChatOptions
    {
        Temperature = 0f,
        MaxOutputTokens = 2048,
        Tools = [.. tools],
    },
};

var agent = new ChatClientAgent(agentOptions, chatClient);

// --- Prompt for topic ---
Console.Write("Enter a research topic: ");
var topic = Console.ReadLine()?.Trim();
if (string.IsNullOrEmpty(topic))
{
    Console.WriteLine("No topic provided. Exiting.");
    return;
}

Console.WriteLine($"\nđź”Ť Researching: {topic}\n");

var systemMessage = new ChatMessage(ChatRole.System, $$"""
    You are a thorough research agent. Follow these steps exactly:

    1. **Search** â€” run 2-3 web searches with varied queries about "{{topic}}".
    2. **Read** â€” for each promising result, fetch the page to get details.
    3. **Note** â€” save key facts, data points, and quotes using the note-taking tool.
    4. **Summarize** â€” review all your notes and write a well-structured summary with
       sections, key findings, and source URLs.

    Be systematic. Use your tools for every step. After the summary, stop.
    """);

var userMessage = new ChatMessage(ChatRole.User,
    $"Please research the following topic thoroughly: {topic}");

var session = await agent.CreateSessionAsync("research", CancellationToken.None);

await foreach (var message in agent.RunStreamingAsync(
    [systemMessage, userMessage],
    session,
    new ChatClientAgentRunOptions(),
    CancellationToken.None))
{
    if (message.Role == ChatRole.Assistant && !string.IsNullOrEmpty(message.Text))
    {
        Console.Write(message.Text);
    }
}

Console.WriteLine();

// Print collected notes
if (notebook.Notes.Count > 0)
{
    Console.WriteLine("\nđź“’ Research Notes Collected:");
    Console.WriteLine(new string('â”€', 50));
    for (var i = 0; i < notebook.Notes.Count; i++)
    {
        Console.WriteLine($"  {i + 1}. {notebook.Notes[i]}");
    }
}

// -------------------------------------------------------------------
// Tool: Web Search (DuckDuckGo HTML â€” no API key required)
// -------------------------------------------------------------------
sealed class WebSearchTool
{
    private static readonly HttpClient s_http = new()
    {
        Timeout = TimeSpan.FromSeconds(15),
        DefaultRequestHeaders =
        {
            { "User-Agent", "ResearchAgent/1.0" },
        },
    };

    [Description("Search the web using DuckDuckGo. Returns a list of result titles, snippets, and URLs.")]
    public async Task<string> SearchAsync(
        [Description("The search query")] string query)
    {
        try
        {
            var url = $"https://html.duckduckgo.com/html/?q={Uri.EscapeDataString(query)}";
            var html = await s_http.GetStringAsync(url);

            var results = ParseSearchResults(html);
            if (results.Count == 0)
                return "No results found.";

            var sb = new StringBuilder();
            sb.AppendLine($"Search results for: {query}\n");
            foreach (var (title, snippet, link) in results.Take(5))
            {
                sb.AppendLine($"**{title}**");
                sb.AppendLine($"  {snippet}");
                sb.AppendLine($"  URL: {link}");
                sb.AppendLine();
            }

            return sb.ToString();
        }
        catch (Exception ex)
        {
            return $"Search failed: {ex.Message}";
        }
    }

    [Description("Fetch a web page and extract its text content. Use this to read the full content of a page found via search.")]
    public async Task<string> FetchPageAsync(
        [Description("The URL of the page to fetch")] string url)
    {
        try
        {
            var html = await s_http.GetStringAsync(url);
            var text = StripHtml(html);

            // Truncate to keep token usage reasonable
            const int maxLength = 4000;
            if (text.Length > maxLength)
                text = text[..maxLength] + "\n\n[... truncated]";

            return $"Content from {url}:\n\n{text}";
        }
        catch (Exception ex)
        {
            return $"Failed to fetch {url}: {ex.Message}";
        }
    }

    private static List<(string Title, string Snippet, string Url)> ParseSearchResults(string html)
    {
        var results = new List<(string, string, string)>();

        // Extract result blocks from DuckDuckGo HTML
        var linkPattern = new Regex(
            @"<a[^>]+class=""result__a""[^>]*href=""([^""]+)""[^>]*>(.*?)</a>",
            RegexOptions.Singleline);
        var snippetPattern = new Regex(
            @"<a[^>]+class=""result__snippet""[^>]*>(.*?)</a>",
            RegexOptions.Singleline);

        var links = linkPattern.Matches(html);
        var snippets = snippetPattern.Matches(html);

        for (var i = 0; i < links.Count && i < 8; i++)
        {
            var rawUrl = WebUtility.HtmlDecode(links[i].Groups[1].Value);
            var title = StripHtmlTags(links[i].Groups[2].Value).Trim();
            var snippet = i < snippets.Count
                ? StripHtmlTags(snippets[i].Groups[1].Value).Trim()
                : "";

            // DuckDuckGo wraps URLs in a redirect; extract the actual URL
            if (rawUrl.Contains("uddg="))
            {
                var match = Regex.Match(rawUrl, @"uddg=([^&]+)");
                if (match.Success)
                    rawUrl = Uri.UnescapeDataString(match.Groups[1].Value);
            }

            if (!string.IsNullOrWhiteSpace(title))
                results.Add((title, snippet, rawUrl));
        }

        return results;
    }

    private static string StripHtmlTags(string html) =>
        Regex.Replace(html, @"<[^>]+>", "").Trim();

    private static string StripHtml(string html)
    {
        // Remove script and style blocks
        html = Regex.Replace(html, @"<(script|style)[^>]*>.*?</\1>", "", RegexOptions.Singleline);
        // Remove tags
        html = StripHtmlTags(html);
        // Decode entities
        html = WebUtility.HtmlDecode(html);
        // Collapse whitespace
        html = Regex.Replace(html, @"\s+", " ");
        return html.Trim();
    }
}

// -------------------------------------------------------------------
// Tool: Note-Taking
// -------------------------------------------------------------------
sealed class Notebook
{
    public List<string> Notes { get; } = [];

    [Description("Save a research note. Use this to record key facts, data points, and findings.")]
    public string AddNote(
        [Description("The note content to save")] string content)
    {
        Notes.Add(content);
        return $"âś… Note #{Notes.Count} saved.";
    }

    [Description("Retrieve all saved research notes.")]
    public string GetNotes()
    {
        if (Notes.Count == 0)
            return "No notes saved yet.";

        var sb = new StringBuilder();
        sb.AppendLine($"Research notes ({Notes.Count} total):\n");
        for (var i = 0; i < Notes.Count; i++)
        {
            sb.AppendLine($"{i + 1}. {Notes[i]}");
        }

        return sb.ToString();
    }
}

